CODE_EXAMPLE:
public List<Widget> retrieveSection(String sectionName) {
    try {
        FileInputStream stream = new FileInputStream(sectionName);
        // ... parse and return
        stream.close();
    } catch (FileNotFoundException e) {
        throw new StorageException("section not found", e);
    }
    return new ArrayList<>();
}

